changeSet.sql:
CREATE TABLE nexus.claude_assisted_remediation_consents (
    id         BIGSERIAL    NOT NULL,
    tenant_id  TEXT         NOT NULL,
    scope      TEXT         NOT NULL,
    ts         TIMESTAMPTZ  NOT NULL,
    granted    BOOLEAN      NOT NULL,
    CONSTRAINT claude_consents_pk PRIMARY KEY (id)
);

-- Insertion-order read within a tenant (the audit trail; nx remediate --history).
CREATE INDEX idx_claude_consents_tenant
    ON nexus.claude_assisted_remediation_consents (tenant_id, id);
CREATE INDEX idx_claude_consents_scope
    ON nexus.claude_assisted_remediation_consents (tenant_id, scope);

ALTER TABLE nexus.claude_assisted_remediation_consents ENABLE ROW LEVEL SECURITY;
ALTER TABLE nexus.claude_assisted_remediation_consents FORCE ROW LEVEL SECURITY;
CREATE POLICY tenant_isolation ON nexus.claude_assisted_remediation_consents
    USING      (tenant_id = current_setting('nexus.tenant', true))
    WITH CHECK (tenant_id = current_setting('nexus.tenant', true));

changeSet.rollback:
DROP POLICY IF EXISTS tenant_isolation ON nexus.claude_assisted_remediation_consents;
ALTER TABLE nexus.claude_assisted_remediation_consents NO FORCE ROW LEVEL SECURITY;
ALTER TABLE nexus.claude_assisted_remediation_consents DISABLE ROW LEVEL SECURITY;
